import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Manages tasks within projects, including creation, assignment, and status updates.',

  dependencies: {
    modules: ['auth'], // Depends on auth for user and session information
  },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks', auth: true }, // Create a new task
    ],
    functions: ['createTask'],
    types: ['Task', 'CreateTaskPayload', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
  ],

  invariants: [
    'A task must always belong to exactly one team.',
    'A task must always be assigned to a user within the same team.',
    'Task titles cannot be empty.',
  ],
});
