import { z } from 'zod';

/**
 * Represents a task in the system.
 */
export interface Task {
  id: string;
  teamId: string;
  title: string;
  description: string | null;
  assigneeId: string | null;
  status: 'todo' | 'in-progress' | 'done';
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Payload for creating a new task.
 */
export interface CreateTaskPayload {
  title: string;
  description?: string | null;
  assigneeId?: string | null;
}

export const CreateTaskPayloadSchema = z.object({
  title: z.string().min(1, 'Task title cannot be empty.'),
  description: z.string().nullable().optional(),
  assigneeId: z.string().uuid('Assignee ID must be a valid UUID.').nullable().optional(),
});

/**
 * Specific error types for task operations.
 */
export type TaskError =
  | { type: 'ValidationError'; message: string; details?: Record<string, string[]> }
  | { type: 'AssigneeNotFound'; message: string }
  | { type: 'AssigneeNotInTeam'; message: string }
  | { type: 'DatabaseError'; message: string };
