import { Database } from 'aether/lib/db';
import { Task } from './types';

/**
 * Inserts a new task into the database.
 *
 * @param db The database client instance.
 * @param taskData The data for the new task.
 * @returns The newly created task object.
 */
export async function insertTask(
  db: Database,
  taskData: {
    teamId: string;
    title: string;
    description: string | null;
    assigneeId: string | null;
    status: 'todo'; // New tasks always start as 'todo'
  }
): Promise<Task> {
  const result = await db.query<Task>(
    `
    INSERT INTO tasks (team_id, title, description, assignee_id, status)
    VALUES ($1, $2, $3, $4, $5)
    RETURNING id, team_id AS "teamId", title, description, assignee_id AS "assigneeId", status, created_at AS "createdAt", updated_at AS "updatedAt";
    `,
    [taskData.teamId, taskData.title, taskData.description, taskData.assigneeId, taskData.status]
  );

  // Assuming the query returns exactly one row for an insert with RETURNING
  return result[0];
}

/**
 * Checks if a user exists and belongs to a specific team.
 *
 * @param db The database client instance.
 * @param userId The ID of the user to check.
 * @param teamId The ID of the team the user should belong to.
 * @returns True if the user exists and belongs to the team, false otherwise.
 */
export async function checkUserInTeam(db: Database, userId: string, teamId: string): Promise<boolean> {
  const result = await db.query<{ exists: boolean }>(
    `
    SELECT EXISTS (
      SELECT 1
      FROM users
      WHERE id = $1 AND team_id = $2
    ) AS exists;
    `,
    [userId, teamId]
  );
  return result[0]?.exists || false;
}
