```aether:modules/tasks/lib/services.ts
import { Database } from 'aether/lib/db';
import { ok, err, Result } from 'aether/lib/result';
import { Task, CreateTaskPayload, TaskError } from './types';
import { insertTask, checkUserInTeam } from './queries';

/**
 * Creates a new task for a given team and user.
 *
 * @param db The database client instance.
 * @param payload The data for the new task.
 * @param teamId The ID of the team the task belongs to.
 * @param userId The ID of the user creating the task.
 * @returns A Result containing the new Task on success, or a TaskError on failure.
 */
export async function createTask(
  db: Database,
  payload: CreateTaskPayload,
  teamId: string,
  userId: string // The user creating the task
): Promise<Result<Task, TaskError>> {
  // If an assignee is provided, validate that they exist and belong to the same team
  if (payload.assigneeId) {
    const assigneeInTeam = await checkUserInTeam(db, payload.assigneeId, teamId);
    if (!assigneeInTeam) {
      return err({
        type: 'AssigneeNotInTeam',
        message: `Assignee with ID ${payload.assigneeId} not found or does not belong to team ${teamId}.`,
      });
    }
  }

  try {
    const newTask = await insertTask(db, {
      teamId,
      title: payload.title,
      description: payload.description ?? null,
      assigneeId: payload.assigneeId ?? null,
      status: 'todo',
    });
    return ok(newTask);
  } catch (error) {
    console.error('Database error creating task:', error);
    return err({ type: 'DatabaseError', message: 'Failed to create task due to a database error.' });
  }
}
