import { Request, Response } from 'aether/lib/types';
import { requireUser } from 'aether/modules/auth/module.contract';
import { parseBody } from 'aether/lib/validate';
import { db } from 'aether/lib/db';
import { createTask } from '../lib/services';
import { CreateTaskPayloadSchema, TaskError } from '../lib/types';

/**
 * Handles the creation of a new task.
 * POST /tasks
 *
 * @param req The incoming request object.
 * @returns A Response object with the created task or an error.
 */
export async function handleCreateTask(req: Request): Promise<Response> {
  // 1. Authenticate the user
  const userResult = await requireUser(req);
  if (userResult.isErr()) {
    return { status: 401, body: { message: userResult.error.message } };
  }
  const user = userResult.value;

  // 2. Validate the request body
  const bodyResult = parseBody(req, CreateTaskPayloadSchema);
  if (bodyResult.isErr()) {
    return { status: 400, body: { message: bodyResult.error.message, details: bodyResult.error.details } };
  }
  const payload = bodyResult.value;

  // 3. Call the service to create the task
  const taskResult = await createTask(db, payload, user.teamId, user.id);

  // 4. Handle the service result
  if (taskResult.isOk()) {
    return { status: 201, body: taskResult.value };
  } else {
    const error: TaskError = taskResult.error;
    switch (error.type) {
      case 'ValidationError':
        return { status: 400, body: { message: error.message, details: error.details } };
      case 'AssigneeNotFound': // This case is handled by AssigneeNotInTeam now
      case 'AssigneeNotInTeam':
        return { status: 400, body: { message: error.message } };
      case 'DatabaseError':
        // Log the error for internal debugging, but return a generic message to the client
        console.error('Error creating task:', error.message);
        return { status: 500, body: { message: 'Failed to create task due to an internal server error.' } };
      default:
        return { status: 500, body: { message: 'An unexpected error occurred.' } };
    }
  }
}
